blocks.body:
{
    "level": "A1–B1",
    "intro": "W tym temacie nauczysz się tworzyć <strong>liczbę mnogą rzeczowników</strong> w języku angielskim, rozpoznawać <strong>wyjątki</strong> oraz odróżniać rzeczowniki używane tylko w liczbie pojedynczej albo tylko w mnogiej.",
    "rules": [
        {
            "label": "+ S",
            "color": "emerald",
            "text": "<strong>Większość rzeczowników</strong> tworzy liczbę mnogą przez dodanie <strong>-s</strong>.",
            "example": "cat → cats, pen → pens, car → cars"
        },
        {
            "label": "+ ES",
            "color": "blue",
            "text": "<strong>-es</strong> dodajemy po <strong>s, ss, x, z, ch, sh</strong> i często po <strong>spółgłosce + o</strong>.",
            "example": "bus → buses, box → boxes, tomato → tomatoes"
        },
        {
            "label": "Y → IES",
            "color": "amber",
            "text": "Po <strong>spółgłosce + y</strong> zmieniamy <strong>y → ies</strong>.",
            "example": "baby → babies, country → countries"
        },
        {
            "label": "F → VES",
            "color": "rose",
            "text": "Część rzeczowników zakończonych na <strong>-f / -fe</strong> zmienia końcówkę na <strong>-ves</strong>.",
            "example": "knife → knives, wolf → wolves"
        },
        {
            "label": "IRREGULAR",
            "color": "purple",
            "text": "Niektóre rzeczowniki mają <strong>nieregularne formy</strong> albo w ogóle się nie zmieniają.",
            "example": "man → men, child → children, sheep → sheep"
        }
    ]
}

{
    "title": "1. Główne sposoby tworzenia liczby mnogiej",
    "intro": "W większości przypadków wystarczy znać cztery podstawowe modele:",
    "items": [
        {
            "label": "+ S",
            "title": "Po prostu dodajemy -s",
            "subtitle": "chair → chairs, notebook → notebooks, apple → apples"
        },
        {
            "label": "+ ES",
            "title": "Dodajemy -es",
            "subtitle": "bus → buses, watch → watches, fox → foxes"
        },
        {
            "label": "Y → IES",
            "title": "Zmieniamy y na ies",
            "subtitle": "lady → ladies, puppy → puppies, city → cities"
        },
        {
            "label": "F/FE → VES",
            "title": "Zmieniamy f / fe na ves",
            "subtitle": "wife → wives, leaf → leaves, knife → knives"
        }
    ]
}

{
    "title": "2. Zasada 1: dodajemy -s",
    "sections": [
        {
            "label": "Podstawowa zasada",
            "color": "emerald",
            "description": "Większość rzeczowników policzalnych tworzy liczbę mnogą przez proste <strong>dodanie -s</strong>.",
            "examples": [
                {
                    "en": "cat → cats",
                    "ua": "kot → koty"
                },
                {
                    "en": "pen → pens",
                    "ua": "długopis → długopisy"
                },
                {
                    "en": "car → cars",
                    "ua": "samochód → samochody"
                },
                {
                    "en": "chair → chairs",
                    "ua": "krzesło → krzesła"
                }
            ]
        },
        {
            "label": "Zwykłe zakończenia",
            "color": "sky",
            "description": "Jeżeli rzeczownik kończy się na samogłoskę albo zwykłą spółgłoskę bez specjalnej reguły pisowni, również po prostu dodajemy <strong>-s</strong>.",
            "examples": [
                {
                    "en": "toy → toys",
                    "ua": "zabawka → zabawki"
                },
                {
                    "en": "day → days",
                    "ua": "dzień → dni"
                },
                {
                    "en": "radio → radios",
                    "ua": "radio → radia"
                },
                {
                    "en": "kangaroo → kangaroos",
                    "ua": "kangur → kangury"
                }
            ]
        },
        {
            "label": "Zgodność w zdaniu",
            "color": "amber",
            "description": "W liczbie mnogiej zmienia się rzeczownik, a główny czasownik zwykle zostaje w formie podstawowej. Ważnym wyjątkiem jest <strong>to be → are</strong>.",
            "examples": [
                {
                    "en": "Cats sleep a lot.",
                    "ua": "podmiot w liczbie mnogiej + czasownik podstawowy"
                },
                {
                    "en": "My friends live in Lviv.",
                    "ua": "podmiot w liczbie mnogiej + czasownik podstawowy"
                },
                {
                    "en": "The books are on the table.",
                    "ua": "podmiot w liczbie mnogiej + are"
                }
            ],
            "note": "📌 Nie dodawaj -s do czasownika po podmiocie w liczbie mnogiej: poprawnie <strong>The cats run</strong>, nie <strong>The cats runs</strong>."
        }
    ]
}

{
    "title": "3. Zasada 2: kiedy dodajemy -es",
    "sections": [
        {
            "label": "Po s, ss, x, z, ch, sh",
            "color": "blue",
            "description": "Po końcówkach syczących i szumiących dodajemy <strong>-es</strong>, żeby wyraz łatwiej było wymówić.",
            "examples": [
                {
                    "en": "bus → buses",
                    "ua": "autobus → autobusy"
                },
                {
                    "en": "kiss → kisses",
                    "ua": "pocałunek → pocałunki"
                },
                {
                    "en": "box → boxes",
                    "ua": "pudełko → pudełka"
                },
                {
                    "en": "church → churches",
                    "ua": "kościół → kościoły"
                },
                {
                    "en": "dish → dishes",
                    "ua": "talerz / danie → talerze / dania"
                }
            ]
        },
        {
            "label": "Spółgłoska + o",
            "color": "purple",
            "description": "Często po <strong>spółgłosce + o</strong> także dodajemy <strong>-es</strong>.",
            "examples": [
                {
                    "en": "tomato → tomatoes",
                    "ua": "pomidor → pomidory"
                },
                {
                    "en": "potato → potatoes",
                    "ua": "ziemniak → ziemniaki"
                },
                {
                    "en": "hero → heroes",
                    "ua": "bohater → bohaterowie"
                },
                {
                    "en": "mosquito → mosquitoes",
                    "ua": "komar → komary"
                }
            ]
        },
        {
            "label": "Wyjątki z -o",
            "color": "sky",
            "description": "Są rzeczowniki zakończone na <strong>-o</strong>, które mimo to tworzą liczbę mnogą przez <strong>-s</strong>.",
            "examples": [
                {
                    "en": "photo → photos",
                    "ua": "zdjęcie → zdjęcia"
                },
                {
                    "en": "piano → pianos",
                    "ua": "fortepian / pianino → fortepiany / pianina"
                },
                {
                    "en": "radio → radios",
                    "ua": "radio → radia"
                },
                {
                    "en": "video → videos",
                    "ua": "wideo → wideo / nagrania"
                }
            ],
            "note": "⚠️ Przy rzeczownikach zakończonych na -o warto sprawdzić słownik, jeśli masz wątpliwości."
        }
    ]
}

{
    "title": "4. Zasada 3: kiedy y zmienia się w ies",
    "sections": [
        {
            "label": "Spółgłoska + y",
            "color": "amber",
            "description": "Jeżeli przed <strong>y</strong> stoi spółgłoska, zmieniamy <strong>y → ies</strong>.",
            "examples": [
                {
                    "en": "country → countries",
                    "ua": "kraj → kraje"
                },
                {
                    "en": "lady → ladies",
                    "ua": "kobieta / pani → kobiety"
                },
                {
                    "en": "family → families",
                    "ua": "rodzina → rodziny"
                },
                {
                    "en": "dictionary → dictionaries",
                    "ua": "słownik → słowniki"
                }
            ]
        },
        {
            "label": "Samogłoska + y",
            "color": "emerald",
            "description": "Jeżeli przed <strong>y</strong> stoi samogłoska, po prostu dodajemy <strong>-s</strong>.",
            "examples": [
                {
                    "en": "toy → toys",
                    "ua": "zabawka → zabawki"
                },
                {
                    "en": "boy → boys",
                    "ua": "chłopiec → chłopcy"
                },
                {
                    "en": "holiday → holidays",
                    "ua": "wakacje / święto → święta"
                },
                {
                    "en": "monkey → monkeys",
                    "ua": "małpa → małpy"
                }
            ]
        },
        {
            "label": "Jak się nie pomylić",
            "color": "sky",
            "description": "Wystarczy spojrzeć na literę przed <strong>y</strong>: spółgłoska → <strong>ies</strong>, samogłoska → <strong>ys</strong>.",
            "examples": [
                {
                    "en": "baby → babies",
                    "ua": "spółgłoska + y"
                },
                {
                    "en": "day → days",
                    "ua": "samogłoska + y"
                }
            ],
            "note": "📌 Ta zasada działa w większości podstawowych przypadków na poziomie A1–A2."
        }
    ]
}

{
    "title": "5. Zasada 4: f / fe → ves",
    "sections": [
        {
            "label": "Typowa zmiana",
            "color": "rose",
            "description": "Wiele rzeczowników zakończonych na <strong>-f</strong> albo <strong>-fe</strong> zmienia końcówkę na <strong>-ves</strong>.",
            "examples": [
                {
                    "en": "wolf → wolves",
                    "ua": "wilk → wilki"
                },
                {
                    "en": "wife → wives",
                    "ua": "żona → żony"
                },
                {
                    "en": "knife → knives",
                    "ua": "nóż → noże"
                },
                {
                    "en": "leaf → leaves",
                    "ua": "liść → liście"
                }
            ]
        },
        {
            "label": "Więcej przykładów",
            "color": "amber",
            "description": "Ten model często pojawia się także w innych codziennych słowach.",
            "examples": [
                {
                    "en": "life → lives",
                    "ua": "życie → życia / żywoty"
                },
                {
                    "en": "thief → thieves",
                    "ua": "złodziej → złodzieje"
                },
                {
                    "en": "shelf → shelves",
                    "ua": "półka → półki"
                },
                {
                    "en": "half → halves",
                    "ua": "połowa → połówki"
                }
            ]
        },
        {
            "label": "Wyjątki",
            "color": "sky",
            "description": "Nie każdy rzeczownik zakończony na <strong>-f</strong> przechodzi w <strong>-ves</strong>. Część dodaje po prostu <strong>-s</strong>, a niektóre mają dwie poprawne formy.",
            "examples": [
                {
                    "en": "roof → roofs",
                    "ua": "dach → dachy"
                },
                {
                    "en": "chief → chiefs",
                    "ua": "szef / wódz → szefowie / wodzowie"
                },
                {
                    "en": "belief → beliefs",
                    "ua": "przekonanie → przekonania"
                },
                {
                    "en": "wharf → wharfs / wharves",
                    "ua": "dwie poprawne formy liczby mnogiej"
                }
            ],
            "note": "⚠️ Takie wyrazy najlepiej zapamiętać osobno."
        }
    ]
}

{
    "title": "6. Nieregularne formy liczby mnogiej",
    "sections": [
        {
            "label": "Zmiana samogłoski",
            "color": "purple",
            "description": "Niektóre rzeczowniki tworzą liczbę mnogą przez zmianę samogłoski w środku wyrazu.",
            "examples": [
                {
                    "en": "man → men",
                    "ua": "mężczyzna → mężczyźni"
                },
                {
                    "en": "woman → women",
                    "ua": "kobieta → kobiety"
                },
                {
                    "en": "foot → feet",
                    "ua": "stopa → stopy"
                },
                {
                    "en": "tooth → teeth",
                    "ua": "ząb → zęby"
                },
                {
                    "en": "goose → geese",
                    "ua": "gęś → gęsi"
                },
                {
                    "en": "mouse → mice",
                    "ua": "mysz → myszy"
                }
            ]
        },
        {
            "label": "Inna forma wyrazu",
            "color": "rose",
            "description": "W części rzeczowników forma liczby mnogiej wygląda zupełnie inaczej niż liczba pojedyncza.",
            "examples": [
                {
                    "en": "child → children",
                    "ua": "dziecko → dzieci"
                },
                {
                    "en": "person → people",
                    "ua": "osoba → ludzie"
                },
                {
                    "en": "ox → oxen",
                    "ua": "wół → woły"
                },
                {
                    "en": "louse → lice",
                    "ua": "wesz → wszy"
                }
            ]
        },
        {
            "label": "Formy klasyczne",
            "color": "amber",
            "description": "Niektóre rzeczowniki naukowe albo formalne zachowują łacińskie lub greckie wzory liczby mnogiej.",
            "examples": [
                {
                    "en": "phenomenon → phenomena",
                    "ua": "zjawisko → zjawiska"
                },
                {
                    "en": "criterion → criteria",
                    "ua": "kryterium → kryteria"
                },
                {
                    "en": "curriculum → curricula",
                    "ua": "program nauczania → programy nauczania"
                }
            ]
        },
        {
            "label": "Ta sama forma",
            "color": "emerald",
            "description": "Niektóre rzeczowniki mają taką samą formę w liczbie pojedynczej i mnogiej.",
            "examples": [
                {
                    "en": "fish → fish",
                    "ua": "ryba → ryby"
                },
                {
                    "en": "sheep → sheep",
                    "ua": "owca → owce"
                },
                {
                    "en": "deer → deer",
                    "ua": "jeleń → jelenie"
                },
                {
                    "en": "aircraft → aircraft",
                    "ua": "samolot → samoloty"
                },
                {
                    "en": "species → species",
                    "ua": "gatunek → gatunki"
                },
                {
                    "en": "shrimp → shrimp",
                    "ua": "krewetka → krewetki"
                }
            ],
            "note": "📌 W szczególnych znaczeniach można czasem spotkać inne formy, ale na poziomie podstawowym ta reguła wystarczy."
        }
    ]
}

{
    "title": "7. Szybka tabela reguł",
    "intro": "Krótkie porównanie najważniejszych modeli tworzenia liczby mnogiej:",
    "rows": [
        {
            "en": "Most nouns",
            "ua": "większość rzeczowników",
            "note": "+ s: cat → cats, pen → pens"
        },
        {
            "en": "After s, ss, x, z, ch, sh",
            "ua": "po s, ss, x, z, ch, sh",
            "note": "+ es: box → boxes, church → churches"
        },
        {
            "en": "Consonant + y",
            "ua": "spółgłoska + y",
            "note": "y → ies: country → countries"
        },
        {
            "en": "Vowel + y",
            "ua": "samogłoska + y",
            "note": "+ s: toy → toys, boy → boys"
        },
        {
            "en": "Many nouns ending in -f / -fe",
            "ua": "wiele wyrazów na -f / -fe",
            "note": "f / fe → ves: knife → knives"
        },
        {
            "en": "Consonant + o",
            "ua": "spółgłoska + o",
            "note": "often + es: hero → heroes, potato → potatoes"
        },
        {
            "en": "Irregular plurals",
            "ua": "formy nieregularne",
            "note": "man → men, child → children, mouse → mice"
        },
        {
            "en": "Same singular and plural",
            "ua": "ta sama forma",
            "note": "sheep → sheep, deer → deer"
        }
    ],
    "warning": "📌 Jeżeli wyraz wygląda nietypowo, sprawdź go w słowniku: najwięcej błędów pojawia się właśnie przy wyjątkach."
}

{
    "title": "8. Rzeczowniki używane tylko w liczbie pojedynczej",
    "sections": [
        {
            "label": "Rzeczowniki niepoliczalne",
            "color": "indigo",
            "description": "Rzeczowniki niepoliczalne zwykle <strong>nie mają liczby mnogiej</strong> i łączą się z czasownikiem w liczbie pojedynczej.",
            "examples": [
                {
                    "en": "water, milk, gold",
                    "ua": "płyny i materiały"
                },
                {
                    "en": "advice, information, happiness, wisdom",
                    "ua": "pojęcia abstrakcyjne"
                },
                {
                    "en": "weather, rain, snow",
                    "ua": "zjawiska naturalne"
                },
                {
                    "en": "coffee, juice, meat",
                    "ua": "jedzenie i napoje jako masa"
                }
            ]
        },
        {
            "label": "Nauki, języki, sporty",
            "color": "sky",
            "description": "Takie wyrazy mogą wyglądać jak liczba mnoga, ale gramatycznie często zachowują się jak liczba pojedyncza.",
            "examples": [
                {
                    "en": "physics, mathematics, history",
                    "ua": "nazwy przedmiotów i nauk"
                },
                {
                    "en": "English, Ukrainian, Chinese",
                    "ua": "nazwy języków"
                },
                {
                    "en": "aerobics, athletics",
                    "ua": "sporty i aktywności"
                }
            ]
        },
        {
            "label": "Typowe zdania",
            "color": "emerald",
            "description": "Z takimi rzeczownikami nie mówimy zwykle <strong>informations</strong> ani <strong>advices</strong> w podstawowym znaczeniu.",
            "examples": [
                {
                    "en": "The information is useful.",
                    "ua": "czasownik w liczbie pojedynczej z information"
                },
                {
                    "en": "Her advice was helpful.",
                    "ua": "czasownik w liczbie pojedynczej z advice"
                },
                {
                    "en": "The weather is cold today.",
                    "ua": "czasownik w liczbie pojedynczej z weather"
                }
            ],
            "note": "📌 W szczególnych kontekstach część z tych słów może mieć formę mnogą, ale w standardowych regułach traktuj je jako singular-only."
        }
    ]
}

{
    "title": "9. Rzeczowniki używane tylko w liczbie mnogiej",
    "sections": [
        {
            "label": "Przedmioty złożone z dwóch części",
            "color": "teal",
            "description": "Niektóre przedmioty złożone z dwóch części występują tylko w liczbie mnogiej. Często używamy z nimi konstrukcji <strong>a pair of</strong>.",
            "examples": [
                {
                    "en": "trousers",
                    "ua": "spodnie"
                },
                {
                    "en": "jeans",
                    "ua": "dżinsy"
                },
                {
                    "en": "glasses",
                    "ua": "okulary"
                },
                {
                    "en": "scissors",
                    "ua": "nożyczki"
                },
                {
                    "en": "binoculars",
                    "ua": "lornetka"
                },
                {
                    "en": "headphones",
                    "ua": "słuchawki"
                }
            ]
        },
        {
            "label": "Inne plural-only nouns",
            "color": "purple",
            "description": "Część rzeczowników nazywa zbiory, wyniki albo utrwalone pojęcia i też występuje tylko w liczbie mnogiej.",
            "examples": [
                {
                    "en": "savings, earnings, goods",
                    "ua": "oszczędności, zarobki, towary"
                },
                {
                    "en": "archives, belongings",
                    "ua": "archiwa, rzeczy osobiste"
                },
                {
                    "en": "outskirts, surroundings, tropics",
                    "ua": "obrzeża, otoczenie, tropiki"
                },
                {
                    "en": "congratulations, customs",
                    "ua": "gratulacje, cło / zwyczaje"
                }
            ]
        },
        {
            "label": "Zmiana znaczenia",
            "color": "amber",
            "description": "Czasem forma pojedyncza istnieje, ale oznacza już inne słowo albo inne znaczenie.",
            "examples": [
                {
                    "en": "glasses = eyewear, glass = material / drinking glass",
                    "ua": "różne znaczenia"
                },
                {
                    "en": "customs = border control / traditions, custom = habit",
                    "ua": "różne znaczenia"
                },
                {
                    "en": "trousers are new / a pair of trousers",
                    "ua": "poprawna zgodność"
                }
            ],
            "note": "📌 Mówimy <strong>These scissors are sharp</strong> oraz <strong>a pair of scissors</strong>."
        }
    ]
}

{
    "title": "10. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pisanie -s zamiast -es po głoskach syczących i szumiących.",
            "wrong": "boxs, churchs, buss",
            "right": "✅ <span class=\"font-mono\">boxes, churches, buses</span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Zmiana y po samogłosce.",
            "wrong": "toies, boies, monkeies",
            "right": "✅ <span class=\"font-mono\">toys, boys, monkeys</span>"
        },
        {
            "label": "Błąd 3",
            "color": "purple",
            "title": "Używanie regular plural tam, gdzie forma jest irregular.",
            "wrong": "childs, mans, mouses",
            "right": "✅ <span class=\"font-mono\">children, men, mice</span>"
        },
        {
            "label": "Błąd 4",
            "color": "sky",
            "title": "Tworzenie liczby mnogiej od rzeczowników niepoliczalnych w ich podstawowym znaczeniu.",
            "wrong": "informations, advices",
            "right": "✅ <span class=\"font-mono\">information, advice</span>"
        },
        {
            "label": "Błąd 5",
            "color": "teal",
            "title": "Stawianie singular article przed plural-only noun.",
            "wrong": "a scissor, a trousers",
            "right": "✅ <span class=\"font-mono\">scissors / a pair of scissors, trousers / a pair of trousers</span>"
        }
    ]
}

